(window.webpackJsonp=window.webpackJsonp||[]).push([[1221],{1490:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for singly-linked list.\\n * function ListNode(val) {\\n *     this.val = val;\\n *     this.next = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{ListNode}</span> <span class=\\"hljs-variable\\">head</span></span>\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{number}</span> <span class=\\"hljs-variable\\">x</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{ListNode}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> partition = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">head, x</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> node=<span class=\\"hljs-keyword\\">new</span> ListNode(<span class=\\"hljs-number\\">0</span>),less=node,\\n      node2=<span class=\\"hljs-keyword\\">new</span> ListNode(<span class=\\"hljs-number\\">0</span>),greater=node2\\n  <span class=\\"hljs-keyword\\">while</span>(head){\\n    <span class=\\"hljs-keyword\\">let</span> curVal=head.val\\n    <span class=\\"hljs-keyword\\">if</span>(curVal&lt;x){\\n      less.next=head\\n      less=less.next\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      greater.next=head\\n      greater=greater.next\\n    }\\n    head=head.next\\n  }\\n  less.next=node2.next\\n  greater.next=<span class=\\"hljs-literal\\">null</span>\\n  <span class=\\"hljs-keyword\\">return</span> node.next\\n};\\n</code></pre>\\n"],"titleSlug":"partition-list","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u5efa\u7acb\u4e00\u4e2a\u94fe\u8868\u5934<code>less</code>\u548c\u94fe\u8868\u5934<code>greater</code>\uff0c\u904d\u5386\u94fe\u8868<code>head</code>\uff0c\u5982\u679c<code>head.val&lt;x</code>\uff0c\u653e\u5165<code>less</code>\u4e2d\uff0c\u5982\u679c<code>head.val&gt;=x</code>\u653e\u5165<code>greater</code>\u4e2d\u3002</p>\\n<p>\u6700\u540e\u5408\u5e76<code>less</code>\u548c<code>greater</code>\u3002</p>\\n","content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u94fe\u8868\u7684\u5934\u8282\u70b9 <code>head</code> \u548c\u4e00\u4e2a\u7279\u5b9a\u503c<em> </em><code>x</code> \uff0c\u8bf7\u4f60\u5bf9\u94fe\u8868\u8fdb\u884c\u5206\u9694\uff0c\u4f7f\u5f97\u6240\u6709 <strong>\u5c0f\u4e8e</strong> <code>x</code> \u7684\u8282\u70b9\u90fd\u51fa\u73b0\u5728 <strong>\u5927\u4e8e\u6216\u7b49\u4e8e</strong> <code>x</code> \u7684\u8282\u70b9\u4e4b\u524d\u3002</p>\\n\\n<p>\u4f60\u5e94\u5f53 <strong>\u4fdd\u7559</strong> \u4e24\u4e2a\u5206\u533a\u4e2d\u6bcf\u4e2a\u8282\u70b9\u7684\u521d\u59cb\u76f8\u5bf9\u4f4d\u7f6e\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n<img alt=\\"\\" src=\\"https://assets.leetcode.com/uploads/2021/01/04/partition.jpg\\" style=\\"width: 662px; height: 222px;\\" />\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [1,4,3,2,5,2], x = 3\\n<strong>\u8f93\u51fa</strong>\uff1a[1,2,2,4,3,5]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [2,1], x = 2\\n<strong>\u8f93\u51fa</strong>\uff1a[1,2]\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u94fe\u8868\u4e2d\u8282\u70b9\u7684\u6570\u76ee\u5728\u8303\u56f4 <code>[0, 200]</code> \u5185</li>\\n\\t<li><code>-100 <= Node.val <= 100</code></li>\\n\\t<li><code>-200 <= x <= 200</code></li>\\n</ul>\\n","title":"86. \u5206\u9694\u94fe\u8868","relatedTags":["\u94fe\u8868","\u53cc\u6307\u9488"],"difficult":"Middle","lang":["javascript"],"uniqueID":"86"}')}}]);